 export class InputRouter {
     /**
-     * @param {Clutter.Actor} topWindowGroup - global.top_window_group
-     *   (above all MetaWindowActors, no restacking fights)
+     * @param {Clutter.Actor} windowGroup - global.window_group
+     * @param {Meta.Display} display
      */
-    constructor(topWindowGroup) {
-        this._topWindowGroup = topWindowGroup;
+    constructor(windowGroup, display) {
+        this._windowGroup = windowGroup;
+        this._display = display;
+        this._restackGuard = false;

         this._stampLayer = new St.Widget({
             name: 'mutter-butter-stamp-layer',
             reactive: false,
             layout_manager: new Clutter.FixedLayout(),
         });
-        // top_window_group is above window_group in the scene graph,
-        // so stamps are always above real windows without needing
-        // to fight Mutter's restacking.
-        topWindowGroup.add_child(this._stampLayer);
+        // Insert stamp layer at the BOTTOM of window_group so stamps
+        // render below full-size MetaWindowActors (like desktop icons).
+        windowGroup.insert_child_below(this._stampLayer, null);
+
+        // Re-lower stamp layer after Mutter restacks windows
+        this._restackedId = display.connect('restacked', () => {
+            if (this._restackGuard)
+                return;
+            this._restackGuard = true;
+            windowGroup.set_child_below_sibling(this._stampLayer, null);
+            this._restackGuard = false;
+        });
     }

